// // This module decrements the counter by 1 on the rising edge of the clock when the enable signal is high. If the reset signal is high, the counter is reset to 0.
module sync_counter(clk, enable, reset, count);

    input clk;
    input enable;
    input reset;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

    always @(posedge clk)
        begin
            if (reset)
                count <= 0;
            else if (enable)
                count <= count + 1;
        end

endmodule
